_BODY = '@torch.no_grad()\ndef sample_dbim(\n    denoiser,\n    diffusion,\n    x,\n    ts,\n    eta=1.0,\n    mask=None,\n    seed=None,\n    **kwargs,\n):\n    """\n    Momentum-Smoothed Adaptive Bridge Sampler (MS-ABS).\n\n    Novel contributions:\n    1. Momentum smoothing of x0_hat predictions (EMA across steps)\n       reduces denoiser variance → more stable bridge transitions.\n    2. Cosine-decaying adaptive eta schedule: starts fully stochastic\n       for exploration, decays to deterministic for sharp refinement.\n    """\n    x_T = x\n    path = []\n    pred_x0 = []\n\n    ones = x.new_ones([x.shape[0]])\n    indices = range(len(ts) - 1)\n    indices = tqdm(indices, disable=(dist.get_rank() != 0))\n\n    nfe = 0\n    generator = BatchedSeedGenerator(seed)\n    first_noise = generator.randn_like(x)\n\n    # --- Novelty 1: Momentum smoothing of x0_hat ---\n    # EMA across steps reduces variance of denoiser predictions,\n    # giving more stable and consistent bridge transitions.\n    prev_x0_hat = None\n    momentum_max = 0.25\n\n    # --- Novelty 2: Adaptive eta schedule ---\n    # Cosine decay from fully stochastic to deterministic.\n    # Early steps: high stochasticity for diversity/exploration.\n    # Late steps: deterministic for sharp, artifact-free output.\n    n_steps = len(ts) - 1\n\n    for step_idx, i in enumerate(indices):\n        s = ts[i]\n        t = ts[i + 1]\n\n        # Denoiser prediction\n        x0_hat = denoiser(x, s * ones)\n\n        # Apply momentum smoothing (EMA)\n        if prev_x0_hat is not None:\n            m = momentum_max * (step_idx / (n_steps - 1)) ** 2\n            x0_hat_smooth = (1.0 - m) * x0_hat + m * prev_x0_hat\n        else:\n            x0_hat_smooth = x0_hat\n        prev_x0_hat = x0_hat_smooth\n\n        if mask is not None:\n            x0_hat_smooth = x0_hat_smooth * mask + x_T * (1 - mask)\n\n        # Get DBIM analytical coefficients\n        a_s, b_s, c_s = [append_dims(item, x0_hat_smooth.ndim) for item in diffusion.noise_schedule.get_abc(s * ones)]\n        a_t, b_t, c_t = [append_dims(item, x0_hat_smooth.ndim) for item in diffusion.noise_schedule.get_abc(t * ones)]\n\n        _, _, rho_s, _ = [append_dims(item, x0_hat_smooth.ndim) for item in diffusion.noise_schedule.get_alpha_rho(s * ones)]\n        alpha_t, _, rho_t, _ = [\n            append_dims(item, x0_hat_smooth.ndim) for item in diffusion.noise_schedule.get_alpha_rho(t * ones)\n        ]\n\n        # Adaptive eta: cosine decay, last 2 steps forced deterministic\n        if step_idx >= n_steps - 2:\n            adaptive_eta = 0.0\n        else:\n            progress = step_idx / max(n_steps - 1, 1)\n            adaptive_eta = eta * 0.5 * (1.0 + torch.cos(torch.tensor(progress * 3.14159265, device=x.device)))\n\n        # DBIM bridge transition with smoothed prediction and adaptive stochasticity\n        omega_st = adaptive_eta * (alpha_t * rho_t) * (1 - rho_t**2 / rho_s**2).sqrt()\n        tmp_var = (c_t**2 - omega_st**2).sqrt() / c_s\n        coeff_xs = tmp_var\n        coeff_x0_hat = b_t - tmp_var * b_s\n        coeff_xT = a_t - tmp_var * a_s\n\n        noise = generator.randn_like(x0_hat_smooth)\n\n        x = coeff_x0_hat * x0_hat_smooth + coeff_xT * x_T + coeff_xs * x + omega_st * noise\n\n        path.append(x.detach().cpu())\n        pred_x0.append(x0_hat_smooth.detach().cpu())\n        nfe += 1\n\n    return x, path, nfe, pred_x0, ts, first_noise\n'

